15	    const cells: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(cells);
17	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
18	      new Set(cells.map((c) => c.join(",")))
19	    );
20	    expect(result).toHaveLength(4);
21	  });
22	  it("live cell with 4 neighbors dies (overpopulation)", () => {
23	    // Center (1,1) has 4 live neighbors: (0,1),(2,1),(1,0),(1,2)
24	    const cells: [number, number][] = [[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]];
25	    const result = nextGeneration(cells);
26	    const resultSet = new Set(result.map((c) => c.join(",")));
